#include "sdat_ref.h"
#include "sdat_avx2.h"
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <x86intrin.h>
typedef struct{uint64_t s;} rng; static int rb(void*c,uint8_t*out,size_t n){rng*r=c;for(size_t i=0;i<n;i++){r->s=r->s*2862933555777941757ULL+3037000493ULL;out[i]=(uint8_t)(r->s>>32);}return 0;}
static uint64_t rd(void){unsigned aux; _mm_lfence(); uint64_t r=__rdtscp(&aux); _mm_lfence(); return r;} static size_t envsz(const char*n,size_t d){char*s=getenv(n); return s?strtoull(s,0,10):d;}
static double bench_sampler(const sdat_table*t,int sda,int avx,size_t n,uint64_t*attempts,uint64_t*rej,uint64_t*bits,uint64_t*bytes,sdat_avx2_stats*as){uint32_t*out=calloc(n,sizeof*out); rng r={123}; sdat_stats st={0}; online_avx2_stats_reset(); uint64_t t0=rd(); if(sda){ if(avx)sda_cdt_avx2_sample_batch(t,rb,&r,out,n,&st); else sda_cdt_ref_sample_batch(t,rb,&r,out,n,&st);} else { if(avx)original_cdt_avx2_sample_batch(t,rb,&r,out,n,&st); else original_cdt_ref_sample_batch(t,rb,&r,out,n,&st);} uint64_t t1=rd(); if(as)*as=*online_avx2_stats(); *attempts=st.attempts;*rej=st.rejections;*bits=st.random_bits;*bytes=st.random_bytes; free(out); return (double)(t1-t0)/(double)n;}
static double bench_lookup(const sdat_table*t,int sda,int avx,size_t n,sdat_avx2_stats*as){uint32_t*out=calloc(n,sizeof*out); online_avx2_stats_reset(); uint64_t t0=rd(); if(t->value_type==SDAT_TYPE_U8){uint8_t*x=calloc(n,sizeof*x); for(size_t i=0;i<n;i++)x[i]=(uint8_t)(i % t->denominator_u64); if(avx)sda_cdt_avx2_lookup_u8_batch(x,n,t->thresholds,t->threshold_count,out); else for(size_t i=0;i<n;i++)out[i]=online_lookup_u8(x[i],t->thresholds,t->threshold_count); free(x);} else if(t->value_type==SDAT_TYPE_U16){uint16_t*x=calloc(n,sizeof*x); for(size_t i=0;i<n;i++)x[i]=(uint16_t)(i % t->denominator_u64); if(avx)original_cdt_avx2_lookup_u16_batch(x,n,t->thresholds,t->threshold_count,out); else for(size_t i=0;i<n;i++)out[i]=online_lookup_u16(x[i],t->thresholds,t->threshold_count); free(x);} else {sdat_u72*x=calloc(n,sizeof*x); for(size_t i=0;i<n;i++)x[i]=(sdat_u72){(uint64_t)i,0}; if(avx){ if(!sda && !strcmp(t->table_family,"original-cdt-table")) original_cdt_avx2_lookup_u72_reverse_batch(x,n,t->thresholds,t->threshold_count,out); else sda_cdt_avx2_lookup_u72_batch(x,n,t->thresholds,t->threshold_count,out);} else { for(size_t i=0;i<n;i++)out[i]=(!sda && !strcmp(t->table_family,"original-cdt-table"))?online_lookup_u72_reverse_tail(x[i],t->thresholds,t->threshold_count):online_lookup_u72(x[i],t->thresholds,t->threshold_count);} free(x);} uint64_t t1=rd(); if(as)*as=*online_avx2_stats(); free(out); (void)sda; return (double)(t1-t0)/(double)n;}
static void row(const sdat_table*t,const char*sf,const char*impl,const char*kind,int batch,double cy,uint64_t att,uint64_t rej,uint64_t bits,uint64_t bytes,sdat_avx2_stats as,size_t n){printf("%s,%s,%s,%s,%s,%s,%d,%d,1,%zu,%.2f,0,0,0,%.2f,%.2f,0,%.6f,%.6f,%.6f,%.6f,%.6f,%zu,%zu,%llu,%llu,%llu,%llu,%llu,%llu,%llu\n",t->scheme,t->parameter_set,sf,t->table_family,impl,kind,batch,!strcmp(impl+strlen(impl)-4,"avx2")?((t->value_type==SDAT_TYPE_U72)?4:8):1,n,cy,cy,cy,n?((double)att/n):0,n?((double)rej/n):0,att?1.0-((double)rej/att):1.0,n?((double)bits/n):0,n?((double)bytes/n):0,t->native_table_bytes,t->packed_bits,(unsigned long long)as.avx2_vector_batches,(unsigned long long)as.avx2_vectorized_samples,(unsigned long long)as.scalar_tail_samples,(unsigned long long)as.fallback_samples,(unsigned long long)as.refill_rounds,(unsigned long long)as.rejected_lanes,(unsigned long long)(as.avx2_vectorized_samples>0));}
int main(void){size_t n=envsz("ONLINE_BENCH_SAMPLES",1000000); int batches[]={1,4,8,16,64,256,1024}; const sdat_table*tabs[]={&original_cdt_table_frodo640,&sda_table_frodo640,&original_cdt_table_frodo976,&sda_table_frodo976,&original_cdt_table_frodo1344,&sda_table_frodo1344,&original_cdt_table_falcon_base,&sda_table_falcon_base}; printf("scheme,parameter_set,sampler_family,table_family,implementation,benchmark_kind,batch_size,lane_width,repetitions,samples_per_repetition,median_cycles_per_sample,MAD,p10,p90,min,max,timer_overhead,attempts_per_sample,rejections_per_sample,acceptance_ratio,random_bits_per_sample,random_bytes_per_sample,native_table_bytes,packed_bits,avx2_vector_batches,vectorized_samples,scalar_tail_samples,fallback_samples,refill_rounds,rejected_lanes,avx2_path_executed\n"); for(size_t ti=0;ti<8;ti++){const sdat_table*t=tabs[ti]; int is_sda=!strcmp(t->table_family,"sda-table"); for(size_t bi=0;bi<sizeof batches/sizeof*batches;bi++){sdat_avx2_stats as={0}; double c=bench_lookup(t,is_sda,0,n,&as); row(t,is_sda?"sda-cdt":"original-cdt",is_sda?"sda-cdt-ref":"original-cdt-ref","lookup-only",batches[bi],c,0,0,0,0,as,n); if(sdat_avx2_cpu_supported()){c=bench_lookup(t,is_sda,1,n,&as); row(t,is_sda?"sda-cdt":"original-cdt",is_sda?"sda-cdt-avx2":"original-cdt-avx2","lookup-only",batches[bi],c,0,0,0,0,as,n);} uint64_t a,r,bits,bytes; c=bench_sampler(t,is_sda,0,n,&a,&r,&bits,&bytes,&as); row(t,is_sda?"sda-cdt":"original-cdt",is_sda?"sda-cdt-ref":"original-cdt-ref","end-to-end",batches[bi],c,a,r,bits,bytes,as,n); if(sdat_avx2_cpu_supported()){c=bench_sampler(t,is_sda,1,n,&a,&r,&bits,&bytes,&as); row(t,is_sda?"sda-cdt":"original-cdt",is_sda?"sda-cdt-avx2":"original-cdt-avx2","end-to-end",batches[bi],c,a,r,bits,bytes,as,n);}}} return 0;}
